/**
 * MiniMarkdown v0.2 вҖ” иҪ»йҮҸ MarkdownвҶ’HTML (Android зҰ»зәҝ)
 * ж”ҜжҢҒ: ж Үйўҳ/зІ—дҪ“/ж–ңдҪ“/д»Јз Ғ/еҲ—иЎЁ/еј•з”Ё/й“ҫжҺҘ/иЎЁж ј/д»Јз Ғеқ—
 */
var marked = (function() {
    'use strict';
    var opts = { breaks: false, gfm: true };
    function setOptions(o) { Object.assign(opts, o); }
    function getDefaults() { return { renderer: {} }; }
    function parse(md) {
        if (!md) return '';
        var h = md;
        // д»Јз Ғеқ—дҝқжҠӨ
        var cbs = [];
        h = h.replace(/```(\w*)\n([\s\S]*?)```/g, function(_, lang, code) {
            var i = cbs.length; cbs.push({ lang: lang, code: code.trimEnd() });
            return '%%CB_' + i + '%%';
        });
        var ics = [];
        h = h.replace(/`([^`]+)`/g, function(_, code) {
            var i = ics.length; ics.push(code); return '%%IC_' + i + '%%';
        });
        h = h.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
        h = h.replace(/^###### (.+)$/gm, '<h6>$1</h6>');
        h = h.replace(/^##### (.+)$/gm, '<h5>$1</h5>');
        h = h.replace(/^#### (.+)$/gm, '<h4>$1</h4>');
        h = h.replace(/^### (.+)$/gm, '<h3>$1</h3>');
        h = h.replace(/^## (.+)$/gm, '<h2>$1</h2>');
        h = h.replace(/^# (.+)$/gm, '<h1>$1</h1>');
        h = h.replace(/^(---|\*\*\*|___)$/gm, '<hr>');
        h = h.replace(/^&gt; (.+)$/gm, '<blockquote>$1</blockquote>');
        h = h.replace(/<\/blockquote>\n<blockquote>/g, '\n');
        h = h.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>');
        h = h.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
        h = h.replace(/\*(.+?)\*/g, '<em>$1</em>');
        h = h.replace(/~~(.+?)~~/g, '<del>$1</del>');
        h = h.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img src="$2" alt="$1">');
        h = h.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');
        h = h.replace(/^[\*\-] (.+)$/gm, '<li>$1</li>');
        h = h.replace(/(<li>.*<\/li>\n?)+/g, '<ul>$&</ul>');
        h = h.replace(/^\d+\. (.+)$/gm, '<li>$1</li>');
        // иЎЁж ј
        h = h.replace(/^\|(.+)\|$/gm, function(line) {
            var cells = line.split('|').filter(function(c) { return c.trim(); });
            if (cells.every(function(c) { return /^[-:]+$/.test(c.trim()); })) return '';
            return '<tr>' + cells.map(function(c) { return '<td>' + c.trim() + '</td>'; }).join('') + '</tr>';
        });
        h = h.replace(/(<tr>.*<\/tr>\n?)+/g, '<table>$&</table>');
        h = h.replace(/\n\n+/g, '</p><p>');
        h = '<p>' + h + '</p>';
        h = h.replace(/<p>\s*<\/p>/g, '');
        h = h.replace(/<p>(<(h[1-6]|ul|ol|table|blockquote|hr|pre)[^>]*>)/g, '$1');
        h = h.replace(/(<\/(h[1-6]|ul|ol|table|blockquote|pre)>)<\/p>/g, '$1');
        h = h.replace(/%%IC_(\d+)%%/g, function(_, i) { return '<code>' + ics[i] + '</code>'; });
        h = h.replace(/%%CB_(\d+)%%/g, function(_, i) {
            var cb = cbs[i];
            return '<pre><code' + (cb.lang ? ' class="language-' + cb.lang + '"' : '') + '>' + cb.code + '</code></pre>';
        });
        if (opts.breaks) h = h.replace(/\n/g, '<br>');
        return h;
    }
    return { setOptions: setOptions, getDefaults: getDefaults, parse: parse };
})();
